13826   // there is some missing dependence edge in the schedule data graph.
13827   struct ScheduleDataCompare {
13828     bool operator()(ScheduleData *SD1, ScheduleData *SD2) const {
13829       return SD2->SchedulingPriority < SD1->SchedulingPriority;
