13835   // and fill the ready-list with initial instructions.
13836   int Idx = 0;
13837   for (auto *I = BS->ScheduleStart; I != BS->ScheduleEnd;
13838        I = I->getNextNode()) {
13839     BS->doForAllOpcodes(I, [this, &Idx, BS](ScheduleData *SD) {
13840       TreeEntry *SDTE = getTreeEntry(SD->Inst);
